const { ethers } = require('ethers');
require('dotenv').config();

// ============================================================
// Configuration - All sensitive values loaded from environment
// ============================================================
const config = {
  rpcUrl: process.env.ETH_RPC_URL || 'http://localhost:8545',
  chainId: parseInt(process.env.CHAIN_ID || '1'),
  gasLimitDefault: parseInt(process.env.GAS_LIMIT || '21000'),
  gasLimitContract: parseInt(process.env.GAS_LIMIT_CONTRACT || '200000'),
};

// ============================================================
// Wallet Manager - Handles wallet creation and signing
// ============================================================
class WalletManager {
  constructor(providerUrl) {
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.wallets = new Map();
  }

  /**
   * Load a wallet from a private key stored in environment variables.
   * IMPORTANT: Never hardcode private keys. Always use environment variables
   * or a secure key management service (e.g., AWS KMS, HashiCorp Vault).
   */
  loadWallet(walletName) {
    const envKey = `WALLET_PRIVATE_KEY_${walletName.toUpperCase()}`;
    const privateKey = process.env[envKey];

    if (!privateKey) {
      throw new Error(
        `Private key not found for wallet "${walletName}". ` +
        `Set the environment variable ${envKey}`
      );
    }

    const wallet = new ethers.Wallet(privateKey, this.provider);
    this.wallets.set(walletName, wallet);

    console.log(`Wallet "${walletName}" loaded: ${wallet.address}`);
    return wallet;
  }

  getWallet(walletName) {
    const wallet = this.wallets.get(walletName);
    if (!wallet) {
      throw new Error(`Wallet "${walletName}" not loaded. Call loadWallet() first.`);
    }
    return wallet;
  }

  async getBalance(walletName) {
    const wallet = this.getWallet(walletName);
    const balance = await this.provider.getBalance(wallet.address);
    return ethers.formatEther(balance);
  }

  async getBalanceOf(address) {
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }
}

// ============================================================
// Transaction Service - Send ETH and interact with contracts
// ============================================================
class TransactionService {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.provider = walletManager.provider;
  }

  /**
   * Send ETH from one wallet to an address
   */
  async sendETH(fromWalletName, toAddress, amountInEther, options = {}) {
    const wallet = this.walletManager.getWallet(fromWalletName);

    // Validate address
    if (!ethers.isAddress(toAddress)) {
      throw new Error(`Invalid Ethereum address: ${toAddress}`);
    }

    const amountWei = ethers.parseEther(amountInEther.toString());

    // Build transaction
    const tx = {
      to: toAddress,
      value: amountWei,
      gasLimit: options.gasLimit || config.gasLimitDefault,
    };

    // Optionally set gas price or let provider estimate
    if (options.maxFeePerGas) {
      tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
      tx.maxPriorityFeePerGas = ethers.parseUnits(
        (options.maxPriorityFeePerGas || '1.5').toString(),
        'gwei'
      );
    }

    console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

    const txResponse = await wallet.sendTransaction(tx);
    console.log(`Transaction submitted: ${txResponse.hash}`);

    // Wait for confirmation
    const receipt = await txResponse.wait(options.confirmations || 1);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    return {
      hash: txResponse.hash,
      from: receipt.from,
      to: receipt.to,
      value: amountInEther,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  /**
   * Send ETH to multiple recipients in sequence
   */
  async batchSendETH(fromWalletName, recipients) {
    const results = [];
    for (const { address, amount } of recipients) {
      try {
        const result = await this.sendETH(fromWalletName, address, amount);
        results.push({ ...result, error: null });
      } catch (error) {
        results.push({ address, amount, error: error.message, status: 'failed' });
      }
    }
    return results;
  }
}

// ============================================================
// Smart Contract Service - Deploy and interact with contracts
// ============================================================
class SmartContractService {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.provider = walletManager.provider;
    this.contracts = new Map();
  }

  /**
   * Load a smart contract instance
   */
  loadContract(name, address, abi, walletName) {
    if (!ethers.isAddress(address)) {
      throw new Error(`Invalid contract address: ${address}`);
    }

    let signerOrProvider;
    if (walletName) {
      signerOrProvider = this.walletManager.getWallet(walletName);
    } else {
      signerOrProvider = this.provider;
    }

    const contract = new ethers.Contract(address, abi, signerOrProvider);
    this.contracts.set(name, { contract, address, abi });

    console.log(`Contract "${name}" loaded at ${address}`);
    return contract;
  }

  getContract(name) {
    const entry = this.contracts.get(name);
    if (!entry) {
      throw new Error(`Contract "${name}" not loaded.`);
    }
    return entry.contract;
  }

  /**
   * Call a read-only function on a contract (no gas required)
   */
  async callFunction(contractName, functionName, ...args) {
    const contract = this.getContract(contractName);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function "${functionName}" not found on contract "${contractName}"`);
    }

    console.log(`Calling ${contractName}.${functionName}(${args.join(', ')})...`);
    const result = await contract[functionName](...args);
    console.log(`Result: ${result}`);
    return result;
  }

  /**
   * Execute a state-changing function on a contract (requires gas)
   */
  async executeFunction(contractName, functionName, args = [], options = {}) {
    const contract = this.getContract(contractName);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function "${functionName}" not found on contract "${contractName}"`);
    }

    const txOptions = {};
    if (options.value) {
      txOptions.value = ethers.parseEther(options.value.toString());
    }
    if (options.gasLimit) {
      txOptions.gasLimit = options.gasLimit;
    } else {
      txOptions.gasLimit = config.gasLimitContract;
    }

    console.log(`Executing ${contractName}.${functionName}(${args.join(', ')})...`);

    const txResponse = await contract[functionName](...args, txOptions);
    console.log(`Transaction submitted: ${txResponse.hash}`);

    const receipt = await txResponse.wait(options.confirmations || 1);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    return {
      hash: txResponse.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      logs: receipt.logs,
    };
  }

  /**
   * Deploy a new smart contract
   */
  async deployContract(walletName, abi, bytecode, constructorArgs = [], options = {}) {
    const wallet = this.walletManager.getWallet(walletName);
    const factory = new ethers.ContractFactory(abi, bytecode, wallet);

    console.log('Deploying contract...');

    const deployOptions = {};
    if (options.gasLimit) {
      deployOptions.gasLimit = options.gasLimit;
    }

    const contract = await factory.deploy(...constructorArgs, deployOptions);
    await contract.waitForDeployment();

    const deployedAddress = await contract.getAddress();
    console.log(`Contract deployed at: ${deployedAddress}`);

    return {
      address: deployedAddress,
      contract,
    };
  }

  /**
   * Listen for contract events
   */
  listenToEvent(contractName, eventName, callback) {
    const contract = this.getContract(contractName);

    contract.on(eventName, (...args) => {
      const event = args[args.length - 1]; // Last arg is the event object
      console.log(`Event "${eventName}" emitted from "${contractName}"`);
      callback(event, ...args.slice(0, -1));
    });

    console.log(`Listening for "${eventName}" events on "${contractName}"...`);
  }

  /**
   * Query past events
   */
  async queryEvents(contractName, eventName, fromBlock = 0, toBlock = 'latest') {
    const contract = this.getContract(contractName);
    const filter = contract.filters[eventName]();
    const events = await contract.queryFilter(filter, fromBlock, toBlock);
    return events;
  }
}

// ============================================================
// ERC20 Token Service - Common ERC20 interactions
// ============================================================
class ERC20Service {
  constructor(smartContractService, walletManager) {
    this.contractService = smartContractService;
    this.walletManager = walletManager;
  }

  static get ABI() {
    return [
      'function name() view returns (string)',
      'function symbol() view returns (string)',
      'function decimals() view returns (uint8)',
      'function totalSupply() view returns (uint256)',
      'function balanceOf(address owner) view returns (uint256)',
      'function transfer(address to, uint256 amount) returns (bool)',
      'function approve(address spender, uint256 amount) returns (bool)',
      'function allowance(address owner, address spender) view returns (uint256)',
      'function transferFrom(address from, address to, uint256 amount) returns (bool)',
      'event Transfer(address indexed from, address indexed to, uint256 value)',
      'event Approval(address indexed owner, address indexed spender, uint256 value)',
    ];
  }

  loadToken(name, tokenAddress, walletName) {
    return this.contractService.loadContract(name, tokenAddress, ERC20Service.ABI, walletName);
  }

  async getTokenInfo(tokenName) {
    const name = await this.contractService.callFunction(tokenName, 'name');
    const symbol = await this.contractService.callFunction(tokenName, 'symbol');
    const decimals = await this.contractService.callFunction(tokenName, 'decimals');
    const totalSupply = await this.contractService.callFunction(tokenName, 'totalSupply');

    return {
      name,
      symbol,
      decimals: Number(decimals),
      totalSupply: ethers.formatUnits(totalSupply, decimals),
    };
  }

  async getBalance(tokenName, address) {
    const contract = this.contractService.getContract(tokenName);
    const decimals = await contract.decimals();
    const balance = await contract.balanceOf(address);
    return ethers.formatUnits(balance, decimals);
  }

  async transfer(tokenName, toAddress, amount) {
    const contract = this.contractService.getContract(tokenName);
    const decimals = await contract.decimals();
    const amountWei = ethers.parseUnits(amount.toString(), decimals);

    return this.contractService.executeFunction(tokenName, 'transfer', [toAddress, amountWei]);
  }

  async approve(tokenName, spenderAddress, amount) {
    const contract = this.contractService.getContract(tokenName);
    const decimals = await contract.decimals();
    const amountWei = ethers.parseUnits(amount.toString(), decimals);

    return this.contractService.executeFunction(tokenName, 'approve', [spenderAddress, amountWei]);
  }
}

