// Utility functions
// ============================================================
class Utils {
  static async getGasPrice(provider) {
    const feeData = await provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : null,
      maxFeePerGas: feeData.maxFeePerGas
        ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei'
        : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei'
        : null,
    };
  }

  static async getBlockNumber(provider) {
    return provider.getBlockNumber();
  }

  static async getTransactionReceipt(provider, txHash) {
    return provider.getTransactionReceipt(txHash);
  }

  static async estimateGas(provider, tx) {
    return provider.estimateGas(tx);
  }

  static async waitForTransaction(provider, txHash, confirmations = 1) {
    return provider.waitForTransaction(txHash, confirmations);
  }
}

