// ============================================================
// Express API Server (optional REST interface)
// ============================================================
function startServer(walletManager, txService, contractService, erc20Service) {
  let express;
  try {
    express = require('express');
  } catch {
    console.log('Express not installed. Skipping API server.');
    console.log('Install with: npm install express');
    return;
  }

  const app = express();
  app.use(express.json());

  // Health check
  app.get('/health', async (req, res) => {
    try {
      const blockNumber = await Utils.getBlockNumber(walletManager.provider);
      res.json({ status: 'ok', blockNumber });
    } catch (e) {
      res.status(500).json({ status: 'error', message: e.message });
    }
  });

  // Get wallet balance
  app.get('/balance/:walletName', async (req, res) => {
    try {
      const balance = await walletManager.getBalance(req.params.walletName);
      const wallet = walletManager.getWallet(req.params.walletName);
      res.json({ address: wallet.address, balance, unit: 'ETH' });
    } catch (e) {
      res.status(400).json({ error: e.message });
    }
  });

  // Get balance of any address
  app.get('/balance/address/:address', async (req, res) => {
    try {
      const balance = await walletManager.getBalanceOf(req.params.address);
      res.json({ address: req.params.address, balance, unit: 'ETH' });
    } catch (e) {
      res.status(400).json({ error: e.message });
    }
  });

  // Send ETH
  app.post('/send', async (req, res) => {
    try {
      const { fromWallet, toAddress, amount } = req.body;
      if (!fromWallet || !toAddress || !amount) {
        return res.status(400).json({ error: 'Missing required fields: fromWallet, toAddress, amount' });
      }
      const result = await txService.sendETH(fromWallet, toAddress, amount);
      res.json(result);
    } catch (e) {
      res.status(500).json({ error: e.message });
    }
  });

  // Get transaction receipt
  app.get('/tx/:hash', async (req, res) => {
    try {
      const receipt = await Utils.getTransactionReceipt(walletManager.provider, req.params.hash);
      if (!receipt) {
        return res.status(404).json({ error: 'Transaction not found' });
      }
      res.json({
        hash: receipt.hash,
        from: receipt.from,
        to: receipt.to,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        status: receipt.status === 1 ? 'success' : 'failed',
      });
    } catch (e) {
      res.status(500).json({ error: e.message });
    }
  });

  // Gas price info
  app.get('/gas', async (req, res) => {
    try {
      const gasInfo = await Utils.getGasPrice(walletManager.provider);
      res.json(gasInfo);
    } catch (e) {
      res.status(500).json({ error: e.message });
    }
  });

  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    console.log(`API server running on port ${PORT}`);
  });

  return app;
}

